let out = String($('Nanda').first().json.output || '');
out = out.split('[BLOCO_UNICO]').join('').split('[/BLOCO_UNICO]').join('').split('**').join('').split('*').join('');
out = out.split(String.fromCharCode(13)).join(' ').split(String.fromCharCode(10)).join(' ');
while (out.indexOf('  ') !== -1) out = out.split('  ').join(' ');
out = out.trim();
if (out.length > 700) out = out.slice(0, 700);
const NL = String.fromCharCode(10);
const profile = 'Voz divertida com sotaque do interior da Bahia, no Brasil';
const director = 'Estilo: tom claro, alegre e acolhedor (sorriso na voz); ritmo rapido e energetico, sem pausas longas.';
const tts_prompt = 'Leia a transcricao a seguir conforme o perfil de audio e a nota de direcao.' + NL + NL + '# Audio Profile' + NL + profile + NL + NL + '# Director note' + NL + director + NL + NL + '## Transcript:' + NL + out;
return [{ json: { tts_prompt: tts_prompt, telefone: $('Parse Webhook').first().json.telefone } }];

const resp = $input.first().json;
let part = {};
try { part = resp.candidates[0].content.parts[0].inlineData; } catch (e) { part = {}; }
const b64 = part.data || '';
const mime = part.mimeType || 'audio/L16;rate=24000';
let rate = 24000, bits = 16;
for (const s of mime.split(';')) {
  const seg = s.trim();
  if (seg.toLowerCase().indexOf('rate=') === 0) { const v = parseInt(seg.split('=')[1]); if (v) rate = v; }
  if (seg.indexOf('audio/L') === 0) { const v = parseInt(seg.split('L')[1]); if (v) bits = v; }
}
if (!b64) { return [{ json: { erro: 'TTS sem audio', telefone: $('Parse Webhook').first().json.telefone } }]; }
const pcm = Buffer.from(b64, 'base64');
const numChannels = 1;
const bytesPerSample = bits / 8;
const blockAlign = numChannels * bytesPerSample;
const byteRate = rate * blockAlign;
const dataSize = pcm.length;
const header = Buffer.alloc(44);
header.write('RIFF', 0);
header.writeUInt32LE(36 + dataSize, 4);
header.write('WAVE', 8);
header.write('fmt ', 12);
header.writeUInt32LE(16, 16);
header.writeUInt16LE(1, 20);
header.writeUInt16LE(numChannels, 22);
header.writeUInt32LE(rate, 24);
header.writeUInt32LE(byteRate, 28);
header.writeUInt16LE(blockAlign, 32);
header.writeUInt16LE(bits, 34);
header.write('data', 36);
header.writeUInt32LE(dataSize, 40);
const wav = Buffer.concat([header, pcm]);
const wavB64 = wav.toString('base64');
return [{ json: { telefone: $('Parse Webhook').first().json.telefone, audioBase64: wavB64, dataUri: 'data:audio/wav;base64,' + wavB64 } }];
